const { ApolloServer, gql } = require('apollo-server');

// Sample data
const users = [
  { id: '1', name: 'Alice' },
  { id: '2', name: 'Bob' },
];

const posts = [
  { id: '1', title: 'Post 1', authorId: '1' },
  { id: '2', title: 'Post 2', authorId: '2' },
];

const comments = [
  { id: '1', content: 'Comment 1', postId: '1', authorId: '2' },
  { id: '2', content: 'Comment 2', postId: '1', authorId: '1' },
];

// GraphQL schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    posts: [Post]
    comments: [Comment]
  }

  type Post {
    id: ID!
    title: String!
    author: User
    comments: [Comment]
  }

  type Comment {
    id: ID!
    content: String!
    post: Post
    author: User
  }

  type Query {
    users: [User]
    posts: [Post]
    comments: [Comment]
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: () => users,
    posts: () => posts,
    comments: () => comments,
  },
  User: {
    posts: (user) => posts.filter(post => post.authorId === user.id),
    comments: (user) => comments.filter(comment => comment.authorId === user.id),
  },
  Post: {
    author: (post) => users.find(user => user.id === post.authorId),
    comments: (post) => comments.filter(comment => comment.postId === post.id),
  },
  Comment: {
    post: (comment) => posts.find(post => post.id === comment.postId),
    author: (comment) => users.find(user => user.id === comment.authorId),
  },
};

// Apollo Server setup
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Implement authentication and authorization checks here if needed
    return {};
  },
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});

